from flask import Flask, request, jsonify, g
from functools import wraps
import sqlite3
from datetime import datetime
import secrets

app = Flask(__name__)
app.config['DATABASE'] = 'oauth_tokens.db'

def get_db():
    db = sqlite3.connect(app.config['DATABASE'])
    db.row_factory = sqlite3.Row
    return db

def init_db():
    with app.app_context():
        db = get_db()
        db.execute('''
            CREATE TABLE IF NOT EXISTS tokens (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                access_token TEXT UNIQUE NOT NULL,
                user_id INTEGER NOT NULL,
                scopes TEXT NOT NULL,
                expires_at TIMESTAMP NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        ''')
        db.execute('''
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                email TEXT
            )
        ''')
        db.commit()
        db.close()

def validate_token(token):
    db = get_db()
    cursor = db.execute(
        'SELECT * FROM tokens WHERE access_token = ? AND expires_at > ?',
        (token, datetime.utcnow())
    )
    token_data = cursor.fetchone()
    db.close()
    return token_data

def check_scope(required_scopes, token_scopes):
    token_scope_list = token_scopes.split() if token_scopes else []
    return all(scope in token_scope_list for scope in required_scopes)

def require_oauth(*required_scopes):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            auth_header = request.headers.get('Authorization')
            
            if not auth_header:
                return jsonify({'error': 'Missing authorization header'}), 401
            
            parts = auth_header.split()
            if len(parts) != 2 or parts[0].lower() != 'bearer':
                return jsonify({'error': 'Invalid authorization header format'}), 401
            
            token = parts[1]
            token_data = validate_token(token)
            
            if not token_data:
                return jsonify({'error': 'Invalid or expired token'}), 401
            
            if required_scopes and not check_scope(required_scopes, token_data['scopes']):
                return jsonify({
                    'error': 'Insufficient scope',
                    'required_scopes': list(required_scopes),
                    'provided_scopes': token_data['scopes'].split()
                }), 403
            
            g.current_user_id = token_data['user_id']
            g.token_scopes = token_data['scopes'].split()
            
            return f(*args, **kwargs)
        return decorated_function
    return decorator

