@app.route('/oauth/token', methods=['POST'])
def create_token():
    data = request.get_json()
    
    if not data or 'user_id' not in data:
        return jsonify({'error': 'user_id required'}), 400
    
    user_id = data['user_id']
    scopes = data.get('scopes', 'read:profile')
    expires_in = data.get('expires_in', 3600)
    
    access_token = secrets.token_urlsafe(32)
    expires_at = datetime.utcnow().timestamp() + expires_in
    expires_at_dt = datetime.fromtimestamp(expires_at)
    
    db = get_db()
    
    cursor = db.execute('SELECT id FROM users WHERE id = ?', (user_id,))
    if not cursor.fetchone():
        db.execute('INSERT INTO users (id, username) VALUES (?, ?)', (user_id, f'user_{user_id}'))
    
    db.execute(
        'INSERT INTO tokens (access_token, user_id, scopes, expires_at) VALUES (?, ?, ?, ?)',
        (access_token, user_id, scopes, expires_at_dt)
    )
    db.commit()
    db.close()
    
    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scopes': scopes
    })

